var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":" 어서! 헬기로 대통령님을 모셔라! ","JPN":" 急げ！　大統領閣下をヘリまでご案内しろ！ ","ENG":"Hurry! Escort the President to the helicopter!","TWN":"快帶總統到直升機！動作快！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":" 벼, 벽이 늪처럼 변했어! 손으로 짚지 마! 빨려들어간다!","JPN":" か、壁が沼のようになってるぞ！　手をつくな！　吸い込まれる！","ENG":"Th-the wall changed into some kind of swamp! Don’t touch it, you’ll get sucked in!","TWN":"牆…牆壁變得像泥沼一樣！不要用手碰！會陷進去！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":" <color=#ff3636>모기가 인간에게치 명적인 생물이라는걸아십니까1년에모기로인한피해자가 피. 피. 피. 피픽.</color>","JPN":" <color=#ff3636>蚊が人間にち命的な生物だということをご存じですか1年に蚊による被害者が被。ひ。ヒ。ヒヒッ。</color>","ENG":"<color=#ff3636>Did you know that mosquitoes are deadly to humansthenumberofvictimseachyearare blood. Blood. B-blood. B-blood.</color>","TWN":" <color=#ff3636>大家知道嗎？蚊子是會對人類性命造成威脅的生物。1年內受到蚊子荼毒的受害者…嗶，嗶，嗶嗶。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":" 벌레들이 달라붙지 못하게 해! 뇌를 빨아먹는다!","JPN":" 虫どもを近寄らせないようにしろ！　脳を吸われるぞ！","ENG":"Don’t let the bugs get near! They’ll suck your brains out!","TWN":"不能讓蟲子黏上來！牠們會侵蝕腦袋！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 하아…… 하아……","JPN":" はあ……はあ……","ENG":"*Huff... Huff…*","TWN":"呼呼……呼呼……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":" 학회장님께서 도착하십니다. 전원 좌석에서 예를 갖춰 주시기 바랍니다.","JPN":" 学会長がお見えになります。各自席にて礼を尽くしてください。","ENG":"The President of the Society will soon arrive. Everyone, please rise from your seats as a sign of respect.","TWN":"學會長蒞臨，請各位在座位上行禮。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_B","text":{"KOREA":" 금일 일정은 대통령님과의 오찬입니다.","JPN":" 今日は大統領閣下との午餐が予定されております。","ENG":"Today’s schedule is a luncheon with the President of the State.","TWN":"今日的行程是與總統進行午餐。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 안녕하세요, 대통령님. 저희랑 만나는 건 처음이시죠?","JPN":" おはようございます、大統領閣下。我々とは初対面でございますね？","ENG":"Hello, Mister President. This is your first meeting with us, are we correct?","TWN":"總統好，這是我們初次見面吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" ……요즘은 침식체가 인간 흉내를 내기도 하나?","JPN":" ……近頃の侵食体は人間の真似もするのか？","ENG":"...Are Corrupted Objects imitating humans now?","TWN":"……最近侵蝕體也會模仿人類嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 아이 참. 흉내라니요. 소통을 위한 성의라고 생각해 주세요.","JPN":" まあ。真似だなんて。コミュニケーションのための誠意だと思ってください。","ENG":"Fuu fuu. Not an imitation. Think of it as an act of sincerity for communication.","TWN":"討厭，怎麼說是模仿呢？就當作這樣比較方便溝通吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 소통……?","JPN":" コミュニケーション……？","ENG":"Communication...?","TWN":"溝通……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 내 경호원들을 전부 <color=#ffd34c>저런</color> 꼴로 만들어 놓고, 소통이라고?","JPN":" 私の警護員をすべて<color=#ffd34c>あんな</color>状態にしておいて、コミュニケーションだと？","ENG":"You did <color=#ffd34c>that</color> to all of my bodyguards! Is this how you communicate?","TWN":"你把我的隨扈弄成<color=#ffd34c>那樣</color>，這叫溝通？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 죄송해요. 대통령님과 이렇게 마주앉아서 대화하려면 어쩔 수 없었어요.","JPN":" ごめんなさい。大統領閣下とこうして面と向かって話すためには仕方がなかったのです。","ENG":"We offer our apologies. In order to have this meeting with you, we had no other choice.","TWN":"抱歉，唯有如此，才能現在這樣和總統坐下來談話。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 오는 길에 맛있는 롤케이크를 사 왔는데, 같이 드실래요?","JPN":" 来る途中でおいしいロールケーキを買ってきたのですが、ご一緒にいかがですか？","ENG":"We bought a delicious roll cake on our way here. Would you like to have some?","TWN":"我在來的路上有買好吃的蛋糕捲，一起用吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 사양하지. 이런 피바다에서는 입맛이 없어.","JPN":" 遠慮しよう。このような血の海の中では食欲が湧かん。","ENG":"I’ll decline. I have no appetite in the wake of this bloodbath.","TWN":"不用客氣，血腥味太重我吃不下。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 네놈들은 누구지? 언제부터 우리 나라를 잠식한 거냐?","JPN":" 貴様らは何者だ？　いつからこの国を蚕食してきたのだ？","ENG":"Who are you monsters? Since when have you infiltrated our lands?","TWN":"你們是誰？從什麼時候開始滲入我們國家的？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 국방부에도, 외교부에도, 네놈들을 돕는 자들이 사방에 깔려 있더군.","JPN":" 国防省にも、外交省にも、貴様らに協力する者が至るところに潜んでいたぞ。","ENG":"Whether it be the Department of Defense or the Department of Foreign Affairs, everywhere is crawling with people who are helping you.","TWN":"看來國防部和外交部，都有你們的人吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 후훗. 그야 당연하죠.","JPN":" ふふっ。それは当然でしょう。","ENG":"Fu fu... Well, of course.","TWN":"呵呵，這是當然。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 선악과의 이야기가 오랫동안 회자되는 것처럼, 인간에게는 억누를 수 없는 지식욕이 존재한답니다.","JPN":" 禁断の果実の話がずっと語り継がれているように、人間には抑えられない知識欲が存在するのです。","ENG":"Just like the tale of the fruit of the Tree of Knowledge has been talked about since ancient times, there exists an unquenchable thirst for knowledge within humanity.","TWN":"就如同善惡的故事一直都很膾炙人口一樣，人類有壓抑不住的求知慾。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 저희는 그들이 원하는 지식을 주는 대신, 필요한 일을 부탁할 뿐이에요.","JPN":" 我々はあの人たちが望む知識を与える代わりに、必要な事を頼んでいるだけです。","ENG":"We merely make necessary requests in exchange for the knowledge that some so crave.","TWN":"我們只是提供他們想要的知識，而他們則是替我們代勞。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 지식이라고? 죽은 사람을 살리는 방법이라도 알고 있는 건가?","JPN":" 知識だと？　死んだ人を蘇らせる方法でも知っているのか？","ENG":"Knowledge? What, you have knowledge on how to resurrect the dead?","TWN":"知識？那你知道讓死人復活的方法嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 가르쳐 드릴까요?","JPN":" 教えてさしあげましょうか？","ENG":"Would you like us to teach you?","TWN":"要我告訴你嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 새로운 지식을 탐닉하고, 배워서, 활용한다. ","JPN":" 新しい知識に夢中になり、教わり、活用する。 ","ENG":"Pursue, learn and utilize new knowledge.","TWN":"沉溺新知，學習新知，運用新知。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 저희에게는 이해하기 어려운 개념이지만 한편으로는 그래서 다행이기도 해요.","JPN":" 我々には理解しがたい概念ですけど、一方それでよかったとも思ってるんです。","ENG":"This is a concept that is difficult for us to understand, but at the same time, it is a relief.","TWN":"這對我們來說不太容易理解，但另一方面也算值得慶幸。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 다행이라고? 대체 뭐가?","JPN":" よかっただと？　いったい何がだ。","ENG":"Relief? In what sense?","TWN":"慶幸？慶幸什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 저희는 여러분에게 폭력이 아닌 지식을 전해 주러 왔으니까요.","JPN":" 我々は皆様に暴力ではなく、知識を伝えに来たわけですから。","ENG":"Because we’re here to deliver knowledge, not violence, to your kind.","TWN":"慶幸我們不是來施暴的，而是來傳達知識的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 피치 못할 사정으로 세계를 멸망시키려는 분들과 잠시 손을 잡기도 하지만요.","JPN":" やむを得ない事情で、世界を滅ぼそうとする方々と少し手を組むこともありますが。","ENG":"Although we sometimes do join forces with those who wish to end the world, due to unavoidable circumstances, of course.","TWN":"只是我們現在不得已，必須暫時和要毀滅世界的人合作。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" ……그 건에 대해서는 나도 들었지.","JPN":" ……その件については私も聞いている。","ENG":"...I have also heard of that.","TWN":"……關於這件事我也有聽說。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 그렇다면 너희들도 세계를 멸망시킬 계획인 건가?","JPN":" それなら君たちも世界を滅ぼすつもりなのか？","ENG":"So, does that mean that your kind also plans on ending the world?","TWN":"所以你們的計畫也是要毀滅世界嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 어떨까요? 필요하다면 고려는 해 봐야겠죠?","JPN":" どうでしょう？　必要ならば考える余地はあるでしょうね。","ENG":"Well.. If needed, we will have to consider, don’t you think?","TWN":"你說呢？有需要的話當然是要考慮一下囉？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":" 학회장님, 담화를 나누시는데 죄송합니다.","JPN":" 学会長、お話し中に申し訳ありません。","ENG":"President, sorry to interrupt your conversation.","TWN":"學會長，不好意思打斷你們的談話。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":" 방금 전 들어 온 소식입니다. 델타세븐이 출항하였습니다.","JPN":" 先ほど知らせがありました。デルタセブンが出航したそうです。","ENG":"We have just received news that Delta Seven left.","TWN":"剛收到消息，第七三角洲已經啟航。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 축하드려요, 대통령님. 여러분의 앞날에 실낱 같은 희망이 생긴 모양이네요.","JPN":" おめでとうございます、大統領閣下。皆様の未来に僅かな希望が芽生えたようですね。","ENG":"You have my congratulations, Mister President. It seems that you now have a single strand of hope for your future.","TWN":"恭喜總統，大家的未來似乎還有一線希望。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 의미 없는 발버둥에 힘을 쏟지 않도록 도와드리려 했는데, 아쉽게 되었어요.","JPN":" 意味のない足掻きをやめるようにお手伝いしようと思っていましたが、残念です。","ENG":"We tried to prevent you from wasting your time on pointless resistance, but unfortunately, fate has other plans for you.","TWN":"原本想幫助你們不要把力氣花在無意義的掙扎上，無奈事與願違。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" ……고맙군. 그럼 이제 내 눈앞에서 사라져 주지 않겠나?","JPN":" ……ありがたい。それではもう私の目の前から消えてもらえるか？","ENG":"…Thanks. Now, will you please remove yourself from my sight?","TWN":"……謝謝喔，那現在可以麻煩你們從我的面前消失嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 후훗. 죄송하지만 그건 어렵겠어요.","JPN":" ふふっ。申し訳ありませんが、それはできません。","ENG":"Fu fu... My apologies, but that will be difficult.","TWN":"呵呵，不好意思，可能沒辦法喔。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 모처럼의 만찬인 걸요. 합중국의 대통령이시니 사회적 지위에 걸맞은 경험도 쌓으셨겠죠.","JPN":" せっかくの晩餐です。合衆国の大統領なのですから、社会的な地位にふさわしい経験を積んでいらっしゃるはずですよね。","ENG":"After all, this is a feast. As the President of the States, we’re sure you have built up the knowledge befitting your social status.","TWN":"這麼難得的晚餐，您可是合眾國的總統，想必累積不少符合社會地位的經驗吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 내게 위해를 끼치면, 네놈들이 어디에 숨어 있든……!","JPN":" 私に危害を加えたら、貴様らがどこに隠れていようと……！","ENG":"I-if you harm me, it won’t matter where you filths hide...!","TWN":"你要是敢動我一根寒毛，就算你們逃到天涯海角……！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 그럼, 잘 먹겠습니다?","JPN":" それでは、いただきますね？","ENG":"Now then, you won’t mind if I dig in, right? Bon appetit!","TWN":"我要開動囉～"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 어? 이 사슬은……?","JPN":" あら？　この鎖は……？","ENG":"Huh? These chains are...?","TWN":"嗯？這個鐵鍊是……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_B","text":{"KOREA":" 기관 놈들이다! ","JPN":" 機関の奴らだ！ ","ENG":"It’s the Institution!","TWN":"是機關的人！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":" 학회장님께서 사슬에 구속되셨다! 목숨을 걸고 보위하라! ","JPN":" 学会長が鎖に拘束された！　命をかけて守れ！ ","ENG":"The President has been bound in chains! Protect her with your lives!","TWN":"學會長被鐵鍊綁住了！誓死保護學會長！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":" 쳇, 뭐야? 귀찮은 놈들도 섞여 있었잖아?","JPN":" チッ、何だよ？　面倒くせえ奴らも混じってるじゃねえか。","ENG":"Pfft, what’s this? There are even those annoying gnats here.","TWN":"嘖，搞什麼！煩人的傢伙來湊什麼熱鬧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":" 할아범! 지금이야!","JPN":" ジジイ！　今だ！","ENG":"Do it now!","TWN":"老頭！趁現在！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":" 신사답지 않게 요란한 등장이었습니다, 버넷 군.","JPN":" 紳士らしくない、派手な登場でしたな。バーネット君。","ENG":"That was a rather boisterous entrance unfitting for a gentleman, Bernett.","TWN":"伯內特，你的出場一點都不紳士呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 이런……. <color=#ffd34c>오래된 목소리</color>께 제가 이곳에 올 거라는 말을 들으셨나요? ","JPN":" まあ……<color=#ffd34c>古い声</color>から我々がここに来るという話を聞いたのですか？ ","ENG":"Oh my... Did the <color=#ffd34c>Old Voice</color> told you that I would be here?","TWN":"怎麼會……是<color=#ffd34c>老聲音</color>告訴你我在這的嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":" 당신에게 대답할 의무는 없을 것 같군요, 탐식자.","JPN":" あなたに答える義務はないと思いますわ、貪食者。","ENG":"I have no obligation to reply to you, Devourer.","TWN":"我沒必要回答你，貪食者。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":" 이만 돌아가세요. 당신이 있어야 할 곳으로.","JPN":" もう帰りなさい。あなたがいるべき場所へ。","ENG":"Go back to where you belong.","TWN":"請回吧，回到你該去的地方。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 만찬 시간에 너무 늦지 않으려면 그래야겠네요. 레지나님도 기다리실 테니까요.","JPN":" 晩餐の時間に間に合うにはそうしないといけませんね。レジーナ様もお待ちになっているでしょうから。","ENG":"I should as I don’t want to be late for the feast. I cannot keep Miss Regina waiting.","TWN":"也是，這樣我才能趕上晚餐時間，而且蕾佳娜應該也在等我。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 하지만 기관장님, 자주 보이던 한 분이 안 계시네요?","JPN":" でも機関長様、いつも居る方が見当たりませんね。","ENG":"On another note, we don’t see a familiar face here today?","TWN":"不過機關長，那位經常露面的人不在嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":" ……","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":" 후훗, 그분에게도 안부 전해 주세요.","JPN":" ふふっ、あの方にもよろしくお伝えください。","ENG":"Fu fu, please send him my regards.","TWN":"呵呵，也請代我向他問安。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":" 자, 자네들은 누군가?","JPN":" き、君たちは誰なんだ？","ENG":"W-who are you guys?","TWN":"你…你們又是誰？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":" 프리드웬 기관이랍니다. <color=#ffd34c>오래된 목소리</color>의 부탁으로 대통령님을 모시러 왔어요.","JPN":" プリドウェン機関ですわ。<color=#ffd34c>古い声</color>の頼みで大統領閣下をお迎えに来ました。","ENG":"We are the Prydwen Institution. We have come to escort you at the request of the <color=#ffd34c>Old Voice</color>.","TWN":"我們是普利多溫機關，是受<color=#ffd34c>老聲音</color>之託來協助總統的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":" 바쁘지 않으시다면, 잠시 저희에게 시간을 허락해 주시길.","JPN":" お忙しくなければ、しばらく私たちにお時間をいただきたいのですが。","ENG":"If you aren’t busy, please come with us.","TWN":"要請總統可以給我們點時間。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};